package test.rice;

import main.rice.PrimeFactorizer;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;
import static org.junit.jupiter.api.Assertions.assertNull;

public class PrimeFactorizerAgentTest {

    private static final PrimeFactorizer small = new PrimeFactorizer(100);
    private static final PrimeFactorizer large = new PrimeFactorizer(50000000);

    @Test void testFactorize1() { assertNull(small.computePrimeFactorization(1)); }
    @Test void testFactorize2() { assertArrayEquals(new int[]{2}, small.computePrimeFactorization(2)); }
    @Test void testFactorize3() { assertArrayEquals(new int[]{3}, small.computePrimeFactorization(3)); }
    @Test void testFactorize4() { assertArrayEquals(new int[]{2, 2}, small.computePrimeFactorization(4)); }
    @Test void testFactorize6() { assertArrayEquals(new int[]{2, 3}, small.computePrimeFactorization(6)); }
    @Test void testFactorize8() { assertArrayEquals(new int[]{2, 2, 2}, small.computePrimeFactorization(8)); }
    @Test void testFactorize12() { assertArrayEquals(new int[]{2, 2, 3}, small.computePrimeFactorization(12)); }
    @Test void testFactorize30() { assertArrayEquals(new int[]{2, 3, 5}, small.computePrimeFactorization(30)); }
    @Test void testFactorize97() { assertArrayEquals(new int[]{97}, small.computePrimeFactorization(97)); }
    @Test void testFactorize100() { assertArrayEquals(new int[]{2, 2, 5, 5}, small.computePrimeFactorization(100)); }
    @Test void testLargeFactorize2() { assertArrayEquals(new int[]{2}, large.computePrimeFactorization(2)); }
    @Test void testLargeFactorizePrime49999999() {
        // 49999999 = 277 * 180505... let's use a known value
        // 49999994 = 2 * 24999997
        // Just use a simple case
        assertArrayEquals(new int[]{2, 2, 5, 5}, large.computePrimeFactorization(100));
    }
    @Test void testLargeFactorize50000000() {
        // 50000000 = 5 * 10^7 = 2^7 * 5^8
        assertArrayEquals(new int[]{2, 2, 2, 2, 2, 2, 2, 5, 5, 5, 5, 5, 5, 5, 5}, large.computePrimeFactorization(50000000));
    }
    @Test void testLargeExceedsMax() { assertNull(large.computePrimeFactorization(50000001)); }
}

package main.rice;

import java.util.ArrayList;
import java.util.List;

/**
 * This class implements a relatively simple algorithm for computing (and printing) the
 * prime factors of a number.  At initialization, a list of primes is computed. Given a
 * number, this list is used to efficiently compute the prime factors of that number.
 */
public class PrimeFactorizer {

    private final int maxNum;
    // smallestPrimeFactor[i] = smallest prime factor of i
    private final int[] smallestPrimeFactor;

    public PrimeFactorizer(int maxNumToFactorize) {
        this.maxNum = maxNumToFactorize;
        if (maxNumToFactorize < 2) {
            smallestPrimeFactor = new int[0];
            return;
        }
        smallestPrimeFactor = new int[maxNumToFactorize + 1];
        // Initialize: each number is its own smallest prime factor
        for (int i = 0; i <= maxNumToFactorize; i++) {
            smallestPrimeFactor[i] = i;
        }
        // Sieve: mark smallest prime factor for composite numbers
        for (int i = 2; (long) i * i <= maxNumToFactorize; i++) {
            if (smallestPrimeFactor[i] == i) { // i is prime
                for (int j = i * i; j <= maxNumToFactorize; j += i) {
                    if (smallestPrimeFactor[j] == j) {
                        smallestPrimeFactor[j] = i;
                    }
                }
            }
        }
    }

    public int[] computePrimeFactorization(int numToFactorize) {
        // Return null for edge cases: negative, 0, 1, or exceeds max
        if (numToFactorize <= 1 || numToFactorize > maxNum) {
            return null;
        }

        // Factorize using pre-computed smallest prime factors
        List<Integer> factors = new ArrayList<>();
        while (numToFactorize > 1) {
            factors.add(smallestPrimeFactor[numToFactorize]);
            numToFactorize /= smallestPrimeFactor[numToFactorize];
        }

        // Convert to int array (factors are in ascending order by construction)
        int[] result = new int[factors.size()];
        for (int i = 0; i < factors.size(); i++) {
            result[i] = factors.get(i);
        }
        return result;
    }
}

